'use client';

import { useAuth, useUser, SignInButton, UserButton } from "@clerk/nextjs";
import { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Bot, User, SendHorizontal, Fingerprint, MapPin, Sparkles } from 'lucide-react';
import Link from 'next/link';
const museumHighlights = [
  {
    id: 1,
    title: 'Modern Arts & Tech',
    description: 'Explore the evolution of early AI and quantum machinery.',
    image: 'data:image/jpeg;base64,',
  },
  {
    id: 2,
    title: 'Nature & Science',
    description: 'Immersive projections of earth and biology.',
    image: 'data:image/jpeg;base64,',
  },
  {
    id: 3,
    title: 'The Time Capsule',
    description: 'Artifacts preserved from the 21st Century.',
    image: 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRSxDrIOUaq7niFKvaHVbtlT8WXtxQrJblggA&s',
  },
  {
    id: 4,
    title: 'Modern Arts & Tech',
    description: 'Explore the evolution of early AI and quantum machinery.',
    image: 'data:image/jpeg;base64,',
  },
  {
    id: 5,
    title: 'Modern Arts & Tech',
    description: 'Explore the evolution of early AI and quantum machinery.',
    image: 'data:image/jpeg;base64,',
  },
  {
    id: 6,
    title: 'Modern Arts & Tech',
    description: 'Explore the evolution of early AI and quantum machinery.',
    image: 'data:image/jpeg;base64,',
  },
];

type Message = { id: number; role: 'user' | 'bot'; content: string };

export default function Home() {
  const { user, isSignedIn, isLoaded } = useUser(); 

  // 2. 🚨 YAHAN ISADMIN DEFINE KARNA HAI (Isi ki wajah se error tha) 👇
  const isAdmin = user?.primaryEmailAddress?.emailAddress?.toLowerCase() === "mohammedibrahimshaikh833@gmail.com";
  // User details yahan se milengi
  const [messages, setMessages] = useState<Message[]>([
    { id: 1, role: 'bot', content: 'Welcome to Aetherium Museum! How can I assist you with tickets today?' },
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // ... useEffect same rahega ...

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage: Message = { id: Date.now(), role: 'user', content: input };
    const updatedMessages = [...messages, userMessage];
    
    setMessages(updatedMessages);
    setInput('');
    setIsLoading(true);

    try {
      // Port check karna: 8000 ya 8001? 
      const response = await fetch('http://localhost:8001/api/chat', { 
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ 
          message: input,
          // Clerk se email nikalne ka sahi tareeka:
          email: user?.primaryEmailAddress?.emailAddress || null,
          history: messages
        }),
      });

      if (!response.ok) throw new Error('Neural Link Timeout');

      const data = await response.json();
      const botMessage: Message = { id: Date.now() + 1, role: 'bot', content: data.reply };
      setMessages((prev) => [...prev, botMessage]);

    } catch (error) {
      console.error("Chat Error:", error);
      setMessages((prev) => [...prev, { 
        id: Date.now() + 1, 
        role: 'bot', 
        content: 'Connection issue. Please check if backend is running.' 
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  // ... return block same rahega ...

 return (
    <main className="min-h-screen bg-slate-50 text-slate-900 flex flex-col font-sans selection:bg-emerald-200 overflow-hidden">
      <div className="max-w-7xl mx-auto w-full p-4 md:p-8 flex-1 flex flex-col h-screen overflow-hidden">
        
        {/* Header */}
        <header className="flex items-center justify-between mb-6 pb-4 border-b border-slate-200 shrink-0">
          <motion.div initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }} className="flex items-center gap-4">
            <div className="p-3 bg-emerald-50 rounded-2xl border border-emerald-100">
              <Fingerprint className="w-8 h-8 text-emerald-500" />
            </div>
            <div>
              <h1 className="text-2xl md:text-3xl font-black tracking-tight text-slate-800">Aetherium</h1>
              <p className="text-[10px] text-emerald-600 font-bold uppercase tracking-wider">Interactive Museum</p>
            </div>
          </motion.div>
          
          <div className="flex items-center gap-4">
            <div className='hidden md:flex items-center gap-2 text-sm font-medium text-slate-500 pr-4 border-r border-slate-200'>
              <MapPin size={16} className="text-emerald-500"/> Mumbai City
            </div>
            
            <div className="pl-2">
              {!isSignedIn ? (
                <a href="/sign-in" className="px-5 py-2 rounded-full bg-emerald-500 hover:bg-emerald-600 text-white transition-all text-sm font-bold shadow-md">
                  Sign In
                </a>
              ) : (
                /* 🚨 FIX: Dono items ko ek single flex div ke andar wrap kar diya */
                <div className="flex items-center gap-4">
                  {/* 🌟 ADMIN BUTTON */}
                  {isAdmin && (
                    <Link 
                      href="/admin" 
                      className="px-4 py-2 bg-slate-900 text-white text-xs font-black uppercase tracking-widest rounded-full hover:bg-emerald-500 transition-colors shadow-md"
                    >
                      Admin HQ
                    </Link>
                  )}
                  
                  <a href="/user/dashboard" className="text-emerald-600 hover:text-emerald-700 transition-colors text-sm font-bold">
                    My Passes
                  </a>
                  <UserButton appearance={{ elements: { avatarBox: "w-9 h-9 border-2 border-emerald-100" }}} />
                </div>
              )}
            </div>
          </div>
        </header>

        {/* Main Grid Section */}
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 flex-1 min-h-0 overflow-hidden">
          
          {/* Left Side: Exhibitions */}
          <div className="lg:col-span-5 h-[600px] overflow-y-auto pr-4 pb-6 scrollbar-hide hidden lg:block relative">
            <div className="sticky top-0 bg-slate-50 z-10 pb-4 pt-1">
              <h2 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em]">Current Exhibitions</h2>
            </div>
            
            <div className="space-y-4">
              <AnimatePresence>
                {museumHighlights.map((highlight, index) => (
                  <motion.div
                    key={highlight.id}
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: index * 0.1 }}
                    className="bg-white p-3 rounded-2xl border border-slate-200 shadow-sm hover:shadow-md transition-all flex items-center gap-4 cursor-pointer group"
                  >
                    <div className="w-20 h-20 rounded-xl overflow-hidden bg-slate-100 shrink-0 relative">
                      <img 
                        src={highlight.image} 
                        alt={highlight.title} 
                        className="absolute inset-0 w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" 
                      />
                    </div>
                    <div>
                      <h3 className="text-md font-bold text-slate-800 group-hover:text-emerald-600 transition-colors">
                        {highlight.title}
                      </h3>
                      <p className="text-xs text-slate-500 mt-1 leading-relaxed line-clamp-2">
                        {highlight.description}
                      </p>
                    </div>
                  </motion.div>
                ))}
              </AnimatePresence>
            </div>
          </div>

          {/* Right Side: Chat Container */}
          <motion.div 
            initial={{ opacity: 0, scale: 0.95 }} 
            animate={{ opacity: 1, scale: 1 }} 
            className="lg:col-span-7 flex flex-col rounded-[2rem] bg-white border border-slate-200 shadow-2xl overflow-hidden self-start"
            style={{ height: '600px' }}
          >
            {/* Chat Header */}
            <div className="p-4 border-b border-slate-100 flex items-center gap-3 bg-slate-50 shrink-0">
              <div className="p-2 bg-emerald-100 rounded-full text-emerald-600">
                <Bot size={20} />
              </div>
              <div>
                <h3 className="font-bold text-slate-800 text-sm">Aetherium AI Guide</h3>
                <div className="flex items-center gap-1">
                  <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span>
                  <span className="text-[10px] text-slate-500 font-bold uppercase tracking-tight">Active Session</span>
                </div>
              </div>
            </div>

            {/* Chat Messages */}
            <div className="flex-1 p-4 md:p-6 space-y-4 overflow-y-auto bg-slate-50/30 scrollbar-hide">
              {messages.map((msg) => (
                <motion.div 
                  key={msg.id} 
                  initial={{ opacity: 0, y: 5 }}
                  animate={{ opacity: 1, y: 0 }}
                  className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
                >
                  <div className={`max-w-[85%] p-3 md:p-4 rounded-2xl text-sm leading-relaxed shadow-sm ${
                    msg.role === 'user' 
                    ? 'bg-emerald-500 text-white rounded-tr-sm' 
                    : 'bg-white border border-slate-200 text-slate-700 rounded-tl-sm'
                  }`}>
                    {msg.content}
                  </div>
                </motion.div>
              ))}
              {isLoading && (
                <div className="flex items-center gap-2 text-slate-400 text-[10px] font-bold italic pl-2">
                  <Sparkles size={12} className="animate-pulse text-emerald-400" /> Thinking...
                </div>
              )}
              <div ref={messagesEndRef} />
            </div>

            {/* Chat Input */}
            <div className="p-4 bg-white border-t border-slate-100 shrink-0">
              <div className="flex items-center bg-slate-50 rounded-full border border-slate-200 focus-within:border-emerald-400 focus-within:ring-2 focus-within:ring-emerald-50 transition-all p-1 pr-2">
                <input
                  type="text"
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  onKeyPress={(e) => e.key === 'Enter' && handleSend()}
                  placeholder="Type a message..."
                  className="flex-1 bg-transparent px-4 py-2 text-sm text-slate-800 placeholder-slate-400 focus:outline-none"
                />
                <button
                  onClick={handleSend}
                  disabled={isLoading}
                  className="p-2.5 rounded-full bg-emerald-500 text-white hover:bg-emerald-600 disabled:opacity-50 transition-all shadow-md"
                >
                  <SendHorizontal size={18} />
                </button>
              </div>
            </div>
          </motion.div>

        </div>
      </div>
    </main>
  );
}